# ╔═╡ d5c8bd5d-75a9-4b38-bb09-946de7828c47
struct MyMatrix{A}
	v::A
end

# ╔═╡ 6b082e58-05df-4972-b96d-fda94486c5ef
begin
	Base.size(x::MyMatrix) = (length(x.v), length(x.v))
	Base.size(x::MyMatrix, i) = size(x)[i]
end

# ╔═╡ 7cf5e6bc-e93f-49fc-b72d-4e94e9fdd215
function Base.getindex(x::MyMatrix, i, j)
	if i == j
		v = x.v[i]
		return v + v^2
	else
		return x.v[i] * x.v[j]
	end
end

