# ╔═╡ 7a448155-9043-43ec-8871-c19bae439abd
f(A::MyMatrix)  = λ ->  1 + mapreduce((v) -> v^2 / (v - λ)  , +, A.v)

# ╔═╡ bf018a41-157c-4b73-86b3-9642b2128ac8
f′(A::MyMatrix) = λ ->      mapreduce((v) -> v^2 / (v - λ)^2, +, A.v)

# ╔═╡ 113e26de-3659-4afb-82ee-13562babe868
function LinearAlgebra.eigmax(A::MyMatrix; tol = eps(2.0), debug = false)
    x0 = maximum(A.v) + maximum(A.v)^2
    δ = f(A)(x0)/f′(A)(x0)
    while abs(δ) > x0 * tol               
        x0 -= δ
        δ = f(A)(x0)/f′(A)(x0) 
        debug && println("x = $x0, δ = $δ") # Debugging
    end
    x0
end

# ╔═╡ 0a026613-8dac-466b-ab5a-2f8621b05ca9
eigmax(diagm(X) + X*X')

