# ╔═╡ f1e5562a-663c-4f4b-a319-672d4a711b5b
# Courtesy of https://github.com/vchuravy/vchuravy.github.io/blob/2609583b4986c2413faa3f70f5153a56af959235/talks/2025_02_24-EVERSE.jl#L803-L847
begin
	const DATA_URI_PATTERN = r"^data:((?:\w+\/(?:(?!;).)+)?)((?:;[\w\W]*?[^;])*),(.+)$"

	struct EmbeddedResource
	    src::AbstractString
	    mime::Union{Nothing,MIME}
	    html_attributes::NTuple{N,Pair} where {N}
	end

	# Usage example: EmbeddedResource("data:image/png;base64,...")
	function EmbeddedResource(data_uri::AbstractString, html_attributes::Pair...)
	    m = match(DATA_URI_PATTERN, data_uri)
	    if length(m.captures) == 3
	        mediatype, base64, data = m.captures
	        mime = MIME(mediatype)
	        EmbeddedResource(data_uri, mime, html_attributes)
	    else
	        error("Unsupported data URI")
	    end
	end

	function Base.show(io::IO, mime::MIME"text/html", r::EmbeddedResource)
	    m = match(DATA_URI_PATTERN, r.src)
	    mediatype, base64, data = m.captures
	    mime_str = string(r.mime)

	    tag = if startswith(mime_str, "image/")
	        :img
	    elseif startswith(mime_str, "audio/")
	        :audio
	    elseif startswith(mime_str, "video/")
	        :video
	    else
	        :data
	    end

	    Base.show(
	        io,
	        mime,
	        @htl("""<$(tag) controls='' src=$(r.src) type=$(r.mime) $(Dict{String,Any}(
	                string(k) => v
	                for (k, v) in r.html_attributes
	            ))></$(tag)>""")
	    )
	end
end

